import os
import time
from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest, REGISTRY
from werkzeug.middleware.dispatcher import DispatcherMiddleware
from prometheus_client import make_wsgi_app
import hashlib
import re

app = Flask(__name__)

# Security: Limit the number of unique metrics to prevent cardinality explosion
MAX_UNIQUE_METRICS = 10000
metric_registry = {}
metric_count = 0

# Global metrics for overall tracking
http_requests_total = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

http_request_duration_seconds = Histogram(
    'http_request_duration_seconds',
    'HTTP request duration in seconds',
    ['method', 'endpoint']
)

# Security: Sanitize input to prevent injection attacks
def sanitize_label_value(value, max_length=100):
    if value is None:
        return 'unknown'
    
    # Convert to string and limit length
    value = str(value)[:max_length]
    
    # Remove any characters that aren't alphanumeric, dash, underscore, or slash
    value = re.sub(r'[^a-zA-Z0-9_\-/.]', '_', value)
    
    # Ensure it's not empty
    if not value:
        return 'unknown'
    
    return value

# Security: Hash sensitive data
def hash_sensitive_data(data):
    if data is None:
        return 'unknown'
    return hashlib.sha256(str(data).encode()).hexdigest()[:16]

# Create or get a metric for a specific user-path combination
def get_or_create_user_path_metric(user_id, path):
    global metric_count
    
    # Security: Sanitize inputs
    sanitized_user_id = sanitize_label_value(user_id, max_length=50)
    sanitized_path = sanitize_label_value(path, max_length=200)
    
    # Security: Hash user_id for privacy
    hashed_user_id = hash_sensitive_data(user_id)
    
    # Create a unique key for this combination
    metric_key = f"{hashed_user_id}_{sanitized_path}"
    
    # Check if we've reached the limit
    if metric_key not in metric_registry and metric_count >= MAX_UNIQUE_METRICS:
        # Return a fallback metric instead of creating new ones
        return None
    
    # Create metric if it doesn't exist
    if metric_key not in metric_registry:
        try:
            # Create a safe metric name
            safe_metric_name = f'http_user_path_requests_{metric_key}'
            safe_metric_name = re.sub(r'[^a-zA-Z0-9_:]', '_', safe_metric_name)
            
            metric = Counter(
                safe_metric_name,
                f'HTTP requests for user-path combination',
                ['user_id_hash', 'path', 'method', 'status']
            )
            metric_registry[metric_key] = metric
            metric_count += 1
        except Exception as e:
            print(f"Error creating metric: {e}")
            return None
    
    return metric_registry[metric_key]

# Session tracking metrics
session_requests = Counter(
    'http_session_requests_total',
    'Total HTTP requests per session',
    ['session_id_hash', 'method', 'status']
)

# Middleware to track requests
@app.before_request
def before_request():
    request.start_time = time.time()

@app.after_request
def after_request(response):
    # Calculate request duration
    request_duration = time.time() - request.start_time
    
    # Get request details
    method = request.method
    path = request.path
    status = response.status_code
    
    # Security: Sanitize path
    sanitized_path = sanitize_label_value(path)
    
    # Get user_id and session_id from headers or query params
    user_id = request.headers.get('X-User-ID') or request.args.get('user_id')
    session_id = request.headers.get('X-Session-ID') or request.args.get('session_id')
    
    # Update global metrics
    http_requests_total.labels(method=method, endpoint=sanitized_path, status=status).inc()
    http_request_duration_seconds.labels(method=method, endpoint=sanitized_path).observe(request_duration)
    
    # Update session metrics if session_id is provided
    if session_id:
        hashed_session_id = hash_sensitive_data(session_id)
        session_requests.labels(
            session_id_hash=hashed_session_id,
            method=method,
            status=status
        ).inc()
    
    # Update user-path specific metrics if user_id is provided
    if user_id:
        user_path_metric = get_or_create_user_path_metric(user_id, path)
        if user_path_metric:
            hashed_user_id = hash_sensitive_data(user_id)
            user_path_metric.labels(
                user_id_hash=hashed_user_id,
                path=sanitized_path,
                method=method,
                status=status
            ).inc()
    
    return response

# Sample endpoints
@app.route('/')
def index():
    return jsonify({'message': 'Hello, World!', 'status': 'ok'})

@app.route('/api/users')
def users():
    return jsonify({'users': ['user1', 'user2', 'user3']})

@app.route('/api/products')
def products():
    return jsonify({'products': ['product1', 'product2', 'product3']})

@app.route('/api/orders')
def orders():
    return jsonify({'orders': ['order1', 'order2']})

@app.route('/health')
def health():
    return jsonify({'status': 'healthy', 'metrics_count': metric_count})

# Metrics endpoint
@app.route('/metrics')
def metrics():
    return generate_latest(REGISTRY)

# Add prometheus wsgi middleware to route /metrics requests
app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
    '/metrics': make_wsgi_app()
})

if __name__ == '__main__':
    # Security: Don't run in debug mode in production
    debug_mode = os.environ.get('FLASK_DEBUG', 'False').lower() == 'true'
    port = int(os.environ.get('PORT', 5000))
    
    app.run(host='0.0.0.0', port=port, debug=debug_mode)